  it('should apply function transformation when string key matches and value is a function', () => {
    plural.addRule('uniqueword123', (w: string) => 'custom_plural_' + w);

    const result = plural('uniqueword123');

    // Original: calls the function -> 'custom_plural_uniqueword123'
    // Mutated: returns the function object itself (not a string)
    expect(result).toBe('custom_plural_uniqueword123');
